def two_sum_sorted(arr, target):
    l, r = 0, len(arr) - 1
    while l < r:
        s = arr[l] + arr[r]
        if s == target:
            return (l, r)
        if s < target:
            l += 1     # need larger total → move left pointer right
        else:
            r -= 1     # need smaller total → move right pointer left
    return None

print(two_sum_sorted([1, 2, 4, 5, 7, 9], 9))   # (1, 4)  → 2 + 7

from collections import deque

def rolling_avg(stream, k):
    win, total = deque(), 0.0
    for x in stream:
        win.append(x); total += x
        if len(win) > k:
            total -= win.popleft()
        if len(win) == k:
            yield total / k

print(list(rolling_avg([1, 2, 3, 4, 5, 6], 3)))
# [2.0, 3.0, 4.0, 5.0]

def merge_sorted(a, b):
    i, j, out = 0, 0, []
    while i < len(a) and j < len(b):
        if a[i] <= b[j]:
            out.append(a[i]); i += 1
        else:
            out.append(b[j]); j += 1
    out.extend(a[i:])
    out.extend(b[j:])
    return out

print(merge_sorted([1, 4, 7], [2, 3, 8]))   # [1, 2, 3, 4, 7, 8]
